/**
 * Notification adapter interface.
 *
 * Adapters handle the delivery of notifications through specific channels
 * (email, webhook, SMS, etc.). The NotificationService delegates to one
 * or more adapters when sending a notification.
 */

export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
}

export interface NotificationAdapter {
  /** Unique name for this adapter (e.g. 'email', 'webhook'). */
  readonly name: string;

  /**
   * Send a notification through this adapter's channel.
   * Returns true if the send succeeded, false otherwise.
   */
  send(payload: NotificationPayload): boolean;
}

/**
 * Email notification adapter.
 *
 * Renders email templates and resolves recipients before sending.
 * In this implementation, emails are collected in an outbox that can be
 * inspected (useful for testing and local development). A production
 * version would delegate to an SMTP client or email API.
 */

import { Logger } from '../utils/logger.js';
import type { NotificationAdapter, NotificationPayload } from './notification-adapter.js';

export interface EmailMessage {
  to: string;
  subject: string;
  html: string;
  sentAt: Date;
}

export interface EmailAdapterOptions {
  /** Sender address shown in the "From" field. */
  from?: string;
  /** Map of recipient aliases to email addresses for recipient resolution. */
  recipientMap?: Record<string, string>;
}

export class EmailAdapter implements NotificationAdapter {
  readonly name = 'email';
  private logger = new Logger('EmailAdapter');
  private outbox: EmailMessage[] = [];
  private from: string;
  private recipientMap: Record<string, string>;

  constructor(options: EmailAdapterOptions = {}) {
    this.from = options.from ?? 'noreply@taskflow.local';
    this.recipientMap = options.recipientMap ?? {};
  }

  /**
   * Resolve a recipient string to an email address.
   *
   * If the recipient is already an email (contains @), it is returned as-is.
   * Otherwise the recipientMap is consulted. If no mapping exists, the raw
   * value is returned so delivery can still be attempted.
   */
  resolveRecipient(recipient: string): string {
    if (recipient.includes('@')) {
      return recipient;
    }
    return this.recipientMap[recipient] ?? recipient;
  }

  /**
   * Render notification body into an HTML email template.
   */
  renderTemplate(subject: string, body: string): string {
    return [
      '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
      `  <h2>${escapeHtml(subject)}</h2>`,
      `  <p>${escapeHtml(body)}</p>`,
      `  <hr />`,
      `  <footer style="color: #888; font-size: 12px;">Sent by TaskFlow Pro</footer>`,
      '</div>',
    ].join('\n');
  }

  /**
   * Send a notification as an email.
   */
  send(payload: NotificationPayload): boolean {
    const to = this.resolveRecipient(payload.recipient);
    const html = this.renderTemplate(payload.subject, payload.body);

    const message: EmailMessage = {
      to,
      subject: payload.subject,
      html,
      sentAt: new Date(),
    };

    this.outbox.push(message);
    this.logger.info(`Email sent to ${to} from ${this.from}: "${payload.subject}"`);
    return true;
  }

  /** Get all sent emails (for testing / inspection). */
  getOutbox(): EmailMessage[] {
    return [...this.outbox];
  }

  /** Clear the outbox. */
  clearOutbox(): void {
    this.outbox = [];
  }
}

/** Basic HTML-entity escaping for template rendering. */
function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

