export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: NotificationAdapter[] = [];

  constructor(private eventBus: EventBus, adapters: NotificationAdapter[] = []) {
    this.adapters = adapters;
    this.registerHandlers();
  }

  /**
   * Add a notification adapter for delivery.
   */
  addAdapter(adapter: NotificationAdapter): void {
    this.adapters.push(adapter);
    this.logger.info(`Adapter registered: ${adapter.name}`);
  }

