import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email-adapter.js';
import type { NotificationPayload } from '../../src/adapters/notification-adapter.js';

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter({
      from: 'test@taskflow.local',
      recipientMap: {
        'user-1': 'alice@example.com',
        'user-2': 'bob@example.com',
      },
    });
  });

  describe('resolveRecipient', () => {
    it('should return email addresses unchanged', () => {
      expect(adapter.resolveRecipient('alice@example.com')).toBe('alice@example.com');
    });

    it('should resolve user IDs via recipientMap', () => {
      expect(adapter.resolveRecipient('user-1')).toBe('alice@example.com');
      expect(adapter.resolveRecipient('user-2')).toBe('bob@example.com');
    });

    it('should return raw value when no mapping exists', () => {
      expect(adapter.resolveRecipient('user-unknown')).toBe('user-unknown');
    });
  });

  describe('renderTemplate', () => {
    it('should produce HTML with subject and body', () => {
      const html = adapter.renderTemplate('Test Subject', 'Test body text');
      expect(html).toContain('<h2>Test Subject</h2>');
      expect(html).toContain('<p>Test body text</p>');
      expect(html).toContain('TaskFlow Pro');
    });

    it('should escape HTML entities in content', () => {
      const html = adapter.renderTemplate('A <b>bold</b> move', 'x > y & z < w');
      expect(html).toContain('&lt;b&gt;bold&lt;/b&gt;');
      expect(html).toContain('x &gt; y &amp; z &lt; w');
    });
  });

  describe('send', () => {
    it('should add message to outbox and return true', () => {
      const payload: NotificationPayload = {
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
      };

      const result = adapter.send(payload);

      expect(result).toBe(true);
      const outbox = adapter.getOutbox();
      expect(outbox).toHaveLength(1);
      expect(outbox[0]?.to).toBe('alice@example.com');
      expect(outbox[0]?.subject).toBe('Order Confirmation');
      expect(outbox[0]?.html).toContain('Your order has been placed.');
      expect(outbox[0]?.sentAt).toBeInstanceOf(Date);
    });

    it('should resolve non-email recipients before sending', () => {
      const payload: NotificationPayload = {
        recipient: 'user-1',
        subject: 'Status Update',
        body: 'Your order shipped.',
      };

      adapter.send(payload);

      const outbox = adapter.getOutbox();
      expect(outbox[0]?.to).toBe('alice@example.com');
    });

    it('should accumulate multiple messages in outbox', () => {
      adapter.send({ recipient: 'a@b.com', subject: 's1', body: 'b1' });
      adapter.send({ recipient: 'c@d.com', subject: 's2', body: 'b2' });

      expect(adapter.getOutbox()).toHaveLength(2);
    });
  });

  describe('outbox management', () => {
    it('should clear outbox', () => {
      adapter.send({ recipient: 'a@b.com', subject: 's', body: 'b' });
      adapter.clearOutbox();
      expect(adapter.getOutbox()).toHaveLength(0);
    });

    it('should return a copy of the outbox', () => {
      adapter.send({ recipient: 'a@b.com', subject: 's', body: 'b' });
      const outbox = adapter.getOutbox();
      outbox.pop();
      expect(adapter.getOutbox()).toHaveLength(1);
    });
  });

  describe('adapter interface', () => {
    it('should have name "email"', () => {
      expect(adapter.name).toBe('email');
    });

    it('should work with default options', () => {
      const defaultAdapter = new EmailAdapter();
      defaultAdapter.send({ recipient: 'x@y.com', subject: 'hi', body: 'hello' });
      expect(defaultAdapter.getOutbox()).toHaveLength(1);
    });
  });
});

